#!/usr/bin/env bash
# python.sh — 规划 Python 进阶课程体系 SOP walkthrough for 青少年编程教育.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="青少年编程教育"
WORKFLOW="规划 Python 进阶课程体系"

usage() {
  cat <<EOF
python.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./python.sh             # interactive
  ./python.sh --dry-run
  ./python.sh --json
  ./python.sh --explain
  ./python.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "规划 Python 进阶课程体系" 工作流。

一句话: 为从 Scratch 毕业或直接入门的10-14岁学生设计24-48课时 Python 课程大纲及配套项目体系。

入门 SOP 共 6 步, 失败模式自检 0 项。

相关心智模型:
  • 制作即学习 (Making Is Learning): 编程教育的核心不是教「编程语言语法」, 而是让学生通过创造可分享的外部作品来建构内部知识 — Papert 的建构主义 (constructionism) 是整个领域的哲学根基
  • 低地板、高天花板、宽墙壁 (Low Floor, High Ceiling, Wide Walls): 好的编程教育工具必须同时满足三个维度 — 入门门槛低 (low floor, 6 岁能开始)、能力上限高 (high ceiling, 能做复杂项目)、创作方向广 (wide walls, 不限于一种

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "学情评估与路径选择: 测评学生现有编程基础（Scratch经验、数学水平、兴趣方向），选择课程路径——路径A: turtle→pygame→web基础；路径B: turtle→数据分析→AI入门 (evidence: [T03-S009])；inputs: 学生档案，outputs: 路径决策+分班建议。"
  "制定学习目标矩阵: 参照 CSTA 标准 (evidence: [T03-S004]) 为每个路径制定「知识/技能/理解」三层目标，时间跨度24课时（基础班）或48课时（进阶班）；inputs: 路径决策，outputs: 目标矩阵表。"
  "拆解单元与项目主题: 每8课时为一个单元，每单元围绕一个驱动项目（如\"制作贪吃蛇游戏\"\"抓取天气数据绘图\"），确保语法知识在项目中自然出现；inputs: 目标矩阵，outputs: 单元大纲草稿。"
  "选择工具与环境: 基础阶段用 Thonny/IDLE 降低配置门槛，进阶阶段迁移至 VS Code 或 Replit (evidence: [T03-S009])；写出环境配置 SOP；inputs: 路径，outputs: 工具选型文档+安装脚本。"
  "设计阶段性里程碑评估: 每单元末设置一个\"展示项目\"，期末设计综合项目；制定代码审查清单（变量命名/注释/模块化）；inputs: 单元大纲，outputs: 评价量规+期末项目说明书。"
  "审核与试讲调整: 找1-2名同行教师审阅大纲，选1个单元做试讲，根据课堂反馈修订；inputs: 完整大纲，outputs: 修订版大纲v1.0。"
)
declare -a FAILURE_MODES=(

)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "python-walkthrough"
fi
